import { useForm } from "react-hook-form";
import { useDispatch } from "react-redux";
import { useNavigate, Link } from "react-router-dom";
import { signUp } from "../api/userApi"; // וודאי שהנתיב נכון
import './auth.css'; // שימוש בקובץ ה-CSS המשותף ל-Login/SignUp

function SignUp() {
    const { register, handleSubmit, formState: { errors } } = useForm();
    const navigate = useNavigate();

    // פונקציית השליחה של הטופס
    const onSubmit = async (data) => {
        try {
            // קריאה לשרת לביצוע הרשמה
            await signUp(data);
            alert("נרשמת בהצלחה! כעת ניתן להתחבר");
            navigate('/login'); // העברה לדף התחברות לאחר הצלחה
        } catch (err) {
            console.error("SignUp failed:", err);
            alert("אופס! נראה שיש תקלה בהרשמה. נסה שוב");
        }
    };

    return (
        <div className="auth-page-container">
            <div className="auth-card">
                <h2 className="auth-title">יצירת חשבון</h2>
                <p className="auth-subtitle">הצטרף לקהילת הרובוטים הגדולה בעולם</p>

                <form className="auth-form" onSubmit={handleSubmit(onSubmit)}>
                    
                    {/* קבוצת שדה: שם מלא */}
                    <div className="input-group">
                        <label className="input-label">שם מלא</label>
                        <input 
                            className={`auth-input ${errors.fullName ? 'input-error' : ''}`}
                            type="text" 
                            placeholder="ישראל ישראלי"
                            {...register("fullName", { required: "זהו שדה חובה" })}
                        />
                        {errors.fullName && <span className="error-message">{errors.fullName.message}</span>}
                    </div>

                    {/* קבוצת שדה: אימייל */}
                    <div className="input-group">
                        <label className="input-label">אימייל</label>
                        <input 
                            className={`auth-input ${errors.email ? 'input-error' : ''}`}
                            type="email" 
                            placeholder="example@mail.com"
                            {...register("email", { 
                                required: "זהו שדה חובה",
                                pattern: { value: /^\S+@\S+$/i, message: "אימייל לא תקין" }
                            })}
                        />
                        {errors.email && <span className="error-message">{errors.email.message}</span>}
                    </div>

                    {/* קבוצת שדה: סיסמה */}
                    <div className="input-group">
                        <label className="input-label">סיסמה</label>
                        <input 
                            className={`auth-input ${errors.password ? 'input-error' : ''}`}
                            type="password" 
                            placeholder="לפחות 6 תווים"
                            {...register("password", { 
                                required: "זהו שדה חובה",
                                minLength: { value: 6, message: "הסיסמה חייבת להכיל לפחות 6 תווים" }
                            })}
                        />
                        {errors.password && <span className="error-message">{errors.password.message}</span>}
                    </div>

                    <button className="auth-submit-btn" type="submit">
                        צור חשבון
                    </button>
                </form>

                {/* פוטר של הכרטיס למעבר להתחברות */}
                <p className="auth-footer">
                    כבר יש לך חשבון? <Link to="/login">התחבר כאן</Link>
                </p>
            </div>
        </div>
    );
}

export default SignUp;
